// Extrair dados do webhook
const body = $input.first().json.body;

return [{
  json: {
    nome: body.nome || '',
    objetivo: body.objetivo || '',
    formato: body.formato || '',
    tiposConteudo: body.tiposConteudo || [],
    formatos: body.formatos || [],
    periodo: body.periodo || {},
    persona: body.persona || '',
    message: `Criar campanha: ${body.nome}. Objetivo: ${body.objetivo}. Formato: ${body.formato}. Tipos: ${body.tiposConteudo?.join(', ')}. Formatos: ${body.formatos?.join(', ')}. Período: ${body.periodo?.inicio} a ${body.periodo?.fim}`
  }
}];
